import{_ as s,c as a,a as e,o as t}from"./app-D9kpUyn_.js";const p={};function i(l,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h1 id="dirty-streams" tabindex="-1"><a class="header-anchor" href="#dirty-streams"><span>Dirty Streams</span></a></h1><p>FluxaORM provides a mechanism to track entity changes (inserts, updates, and deletes) using Redis Streams. When an entity is modified and flushed, events are automatically published to registered Redis Streams. Consumers can then process these events asynchronously.</p><h2 id="registering-redis-streams" tabindex="-1"><a class="header-anchor" href="#registering-redis-streams"><span>Registering Redis Streams</span></a></h2><p>Before dirty streams can be used, the underlying Redis Stream must be registered using <code>registry.RegisterRedisStream()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"></span>
<span class="line">registry <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRegistry</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">registry<span class="token punctuation">.</span><span class="token function">RegisterRedis</span><span class="token punctuation">(</span><span class="token string">&quot;localhost:6379&quot;</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">)</span></span>
<span class="line">registry<span class="token punctuation">.</span><span class="token function">RegisterRedisStream</span><span class="token punctuation">(</span><span class="token string">&quot;dirty_AllChanges&quot;</span><span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The first argument is the stream name, and the second is the Redis pool code where the stream will be stored.</p><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>When you define <code>dirty</code> tags on entities, FluxaORM automatically registers the corresponding <code>dirty_</code> prefixed streams during <code>registry.Validate()</code>. You only need to call <code>RegisterRedisStream()</code> manually for custom (non-dirty) streams.</p></div><h2 id="defining-dirty-streams-on-entities" tabindex="-1"><a class="header-anchor" href="#defining-dirty-streams-on-entities"><span>Defining Dirty Streams on Entities</span></a></h2><p>Use the <code>dirty</code> struct tag on entity fields to declare which streams receive events when the entity changes. The tag is placed on the <code>ID</code> field (for insert/update/delete triggers) or on specific fields (for update-only triggers when that field changes).</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> UserEntity <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID    <span class="token builtin">uint64</span> <span class="token string">\`orm:&quot;dirty=AllChanges,NewUsers:add,DeletedUsers:delete,EmailChanged:add&quot;\`</span></span>
<span class="line">    Name  <span class="token builtin">string</span></span>
<span class="line">    Email <span class="token builtin">string</span> <span class="token string">\`orm:&quot;dirty=EmailChanged&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> ProductEntity <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID    <span class="token builtin">uint32</span> <span class="token string">\`orm:&quot;dirty=AllChanges,ProductAddedDeleted:add|delete&quot;\`</span></span>
<span class="line">    Name  <span class="token builtin">string</span></span>
<span class="line">    Price <span class="token builtin">float64</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This example creates five dirty Redis Streams (all automatically prefixed with <code>dirty_</code>):</p><ul><li><code>dirty_AllChanges</code> -- triggered when <code>UserEntity</code> or <code>ProductEntity</code> is inserted, updated, or deleted</li><li><code>dirty_NewUsers</code> -- triggered when <code>UserEntity</code> is inserted</li><li><code>dirty_DeletedUsers</code> -- triggered when <code>UserEntity</code> is deleted</li><li><code>dirty_EmailChanged</code> -- triggered when <code>UserEntity</code> is inserted or when <code>Email</code> is changed</li><li><code>dirty_ProductAddedDeleted</code> -- triggered when <code>ProductEntity</code> is inserted or deleted</li></ul><h3 id="tag-syntax" tabindex="-1"><a class="header-anchor" href="#tag-syntax"><span>Tag Syntax</span></a></h3><p>On the <code>ID</code> field, the syntax is:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">dirty=StreamName              // triggers on add, edit, delete</span>
<span class="line">dirty=StreamName:add          // triggers only on add</span>
<span class="line">dirty=StreamName:delete       // triggers only on delete</span>
<span class="line">dirty=StreamName:add|delete   // triggers on add and delete</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>On other fields, the syntax is:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">dirty=StreamName              // triggers on edit (when this field changes)</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>You can specify multiple streams separated by commas:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">dirty=Stream1,Stream2:add,Stream3:delete</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="publishing-events" tabindex="-1"><a class="header-anchor" href="#publishing-events"><span>Publishing Events</span></a></h2><p>When entities are flushed (via <code>ctx.Flush()</code>), FluxaORM automatically publishes dirty events to the appropriate Redis Streams based on the entity&#39;s <code>dirty</code> tag configuration. This happens transparently as part of the flush pipeline.</p><h2 id="the-event-broker" tabindex="-1"><a class="header-anchor" href="#the-event-broker"><span>The Event Broker</span></a></h2><p>The <code>EventBroker</code> is the central interface for working with Redis Streams. You can access it from the context:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">broker <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>The <code>EventBroker</code> interface provides the following methods:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> EventBroker <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">Publish</span><span class="token punctuation">(</span>stream <span class="token builtin">string</span><span class="token punctuation">,</span> body <span class="token keyword">interface</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> meta <span class="token operator">...</span><span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>id <span class="token builtin">string</span><span class="token punctuation">,</span> err <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">ConsumerSingle</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> stream <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>EventsConsumer<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">ConsumerMany</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> stream <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>EventsConsumer<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">NewFlusher</span><span class="token punctuation">(</span><span class="token punctuation">)</span> EventFlusher</span>
<span class="line">    <span class="token function">GetStreamsStatistics</span><span class="token punctuation">(</span>stream <span class="token operator">...</span><span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>RedisStreamStatistics<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">GetStreamStatistics</span><span class="token punctuation">(</span>stream <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>RedisStreamStatistics<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="publishing-custom-events" tabindex="-1"><a class="header-anchor" href="#publishing-custom-events"><span>Publishing Custom Events</span></a></h3><p>You can also publish events manually to any registered stream:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">broker <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> OrderEvent <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    OrderID <span class="token builtin">uint64</span></span>
<span class="line">    Status  <span class="token builtin">string</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">id<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">Publish</span><span class="token punctuation">(</span><span class="token string">&quot;my-stream&quot;</span><span class="token punctuation">,</span> OrderEvent<span class="token punctuation">{</span>OrderID<span class="token punctuation">:</span> <span class="token number">123</span><span class="token punctuation">,</span> Status<span class="token punctuation">:</span> <span class="token string">&quot;completed&quot;</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>body</code> is serialized using MessagePack. You can also pass optional key-value metadata as additional string arguments:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">id<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">Publish</span><span class="token punctuation">(</span><span class="token string">&quot;my-stream&quot;</span><span class="token punctuation">,</span> body<span class="token punctuation">,</span> <span class="token string">&quot;key1&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;value1&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;key2&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;value2&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="batch-publishing-with-eventflusher" tabindex="-1"><a class="header-anchor" href="#batch-publishing-with-eventflusher"><span>Batch Publishing with EventFlusher</span></a></h3><p>For better performance when publishing many events, use <code>EventFlusher</code> to batch events and send them in a single Redis pipeline:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">flusher <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">NewFlusher</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">for</span> i <span class="token operator">:=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">100</span><span class="token punctuation">;</span> i<span class="token operator">++</span> <span class="token punctuation">{</span></span>
<span class="line">    err <span class="token operator">:=</span> flusher<span class="token punctuation">.</span><span class="token function">Publish</span><span class="token punctuation">(</span><span class="token string">&quot;my-stream&quot;</span><span class="token punctuation">,</span> MyEvent<span class="token punctuation">{</span>ID<span class="token punctuation">:</span> i<span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">err <span class="token operator">:=</span> flusher<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// sends all 100 events in one pipeline call</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="consuming-events" tabindex="-1"><a class="header-anchor" href="#consuming-events"><span>Consuming Events</span></a></h2><p>FluxaORM provides two consumer types:</p><ul><li><code>ConsumerSingle</code> -- creates a single consumer named <code>consumer-single</code>. Only one instance should run at a time for a given stream.</li><li><code>ConsumerMany</code> -- creates a consumer with a unique, randomly generated name. Multiple instances can run in parallel to scale consumption.</li></ul><h3 id="single-consumer" tabindex="-1"><a class="header-anchor" href="#single-consumer"><span>Single Consumer</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">broker <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">consumer<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">ConsumerSingle</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;test-stream&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">defer</span> consumer<span class="token punctuation">.</span><span class="token function">Cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span>events <span class="token punctuation">[</span><span class="token punctuation">]</span>fluxaorm<span class="token punctuation">.</span>Event<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> event <span class="token operator">:=</span> <span class="token keyword">range</span> events <span class="token punctuation">{</span></span>
<span class="line">        event<span class="token punctuation">.</span><span class="token function">ID</span><span class="token punctuation">(</span><span class="token punctuation">)</span>                     <span class="token comment">// Redis stream message ID</span></span>
<span class="line">        event<span class="token punctuation">.</span><span class="token function">Tag</span><span class="token punctuation">(</span><span class="token string">&quot;key1&quot;</span><span class="token punctuation">)</span>             <span class="token comment">// read a metadata tag</span></span>
<span class="line">        <span class="token keyword">var</span> data MyStruct</span>
<span class="line">        err <span class="token operator">:=</span> event<span class="token punctuation">.</span><span class="token function">Unserialize</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>data<span class="token punctuation">)</span> <span class="token comment">// deserialize the body</span></span>
<span class="line">        <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">return</span> err</span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>Consume</code> method accepts:</p><ol><li><code>count</code> -- maximum number of events to process per batch</li><li><code>blockTime</code> -- how long to block waiting for new events</li><li><code>handler</code> -- callback function that receives a slice of events</li></ol><h3 id="multiple-consumers" tabindex="-1"><a class="header-anchor" href="#multiple-consumers"><span>Multiple Consumers</span></a></h3><p>When a single consumer cannot keep up, use <code>ConsumerMany</code> to run multiple consumers in parallel. Each consumer receives a different subset of events from the same stream:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">broker <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">consumer1<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">ConsumerMany</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;my-stream&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">defer</span> consumer1<span class="token punctuation">.</span><span class="token function">Cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">consumer2<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">ConsumerMany</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;my-stream&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">defer</span> consumer2<span class="token punctuation">.</span><span class="token function">Cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">go</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    err <span class="token operator">:=</span> consumer1<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span>events <span class="token punctuation">[</span><span class="token punctuation">]</span>fluxaorm<span class="token punctuation">.</span>Event<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// process events...</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">go</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    err <span class="token operator">:=</span> consumer2<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span>events <span class="token punctuation">[</span><span class="token punctuation">]</span>fluxaorm<span class="token punctuation">.</span>Event<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// process events...</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="event-interface" tabindex="-1"><a class="header-anchor" href="#event-interface"><span>Event Interface</span></a></h2><p>Each event passed to the handler implements the <code>Event</code> interface:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> Event <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">Ack</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">error</span></span>
<span class="line">    <span class="token function">ID</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span></span>
<span class="line">    <span class="token function">Tag</span><span class="token punctuation">(</span>key <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>value <span class="token builtin">string</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">Unserialize</span><span class="token punctuation">(</span>val <span class="token keyword">interface</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token builtin">error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>ID()</code></td><td>Returns the Redis stream message ID</td></tr><tr><td><code>Tag(key)</code></td><td>Returns the value of a metadata tag set during publishing</td></tr><tr><td><code>Unserialize(val)</code></td><td>Deserializes the MessagePack-encoded body into the provided value</td></tr><tr><td><code>Ack()</code></td><td>Manually acknowledges the event (removes it from the pending list)</td></tr></tbody></table><h3 id="automatic-acknowledgment" tabindex="-1"><a class="header-anchor" href="#automatic-acknowledgment"><span>Automatic Acknowledgment</span></a></h3><p>By default, all events passed to the handler function are automatically acknowledged (and deleted from the stream) when the handler returns without error. If you want to acknowledge an event earlier, call <code>event.Ack()</code> inside the handler:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span>events <span class="token punctuation">[</span><span class="token punctuation">]</span>fluxaorm<span class="token punctuation">.</span>Event<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> event <span class="token operator">:=</span> <span class="token keyword">range</span> events <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// process event...</span></span>
<span class="line">        err <span class="token operator">:=</span> event<span class="token punctuation">.</span><span class="token function">Ack</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// acknowledge immediately</span></span>
<span class="line">        <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">return</span> err</span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="auto-claiming-pending-events" tabindex="-1"><a class="header-anchor" href="#auto-claiming-pending-events"><span>Auto-Claiming Pending Events</span></a></h2><p>If a consumer crashes or fails to process events, those events remain in the pending list. Use <code>AutoClaim</code> to reclaim and reprocess pending events that have been idle for longer than a specified duration:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">consumer<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">ConsumerMany</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;my-stream&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">defer</span> consumer<span class="token punctuation">.</span><span class="token function">Cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">AutoClaim</span><span class="token punctuation">(</span><span class="token number">1000</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span>events <span class="token punctuation">[</span><span class="token punctuation">]</span>fluxaorm<span class="token punctuation">.</span>Event<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// reprocess claimed events...</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>AutoClaim</code> accepts:</p><ol><li><code>count</code> -- maximum number of pending events to claim per batch</li><li><code>minIdle</code> -- minimum idle time before an event can be claimed</li><li><code>handler</code> -- callback function to process the claimed events</li></ol><h2 id="stream-statistics" tabindex="-1"><a class="header-anchor" href="#stream-statistics"><span>Stream Statistics</span></a></h2><p>Use the <code>EventBroker</code> to retrieve statistics about registered streams:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">broker <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetEventBroker</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Single stream</span></span>
<span class="line">stat<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">GetStreamStatistics</span><span class="token punctuation">(</span><span class="token string">&quot;dirty_AllChanges&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> stat <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    stat<span class="token punctuation">.</span>Stream             <span class="token comment">// stream name</span></span>
<span class="line">    stat<span class="token punctuation">.</span>RedisPool          <span class="token comment">// Redis pool code</span></span>
<span class="line">    stat<span class="token punctuation">.</span>Len                <span class="token comment">// number of messages in the stream</span></span>
<span class="line">    stat<span class="token punctuation">.</span>OldestEventSeconds <span class="token comment">// seconds since the oldest pending event</span></span>
<span class="line">    <span class="token keyword">if</span> stat<span class="token punctuation">.</span>Group <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>Group                 <span class="token comment">// consumer group name</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>Lag                   <span class="token comment">// group lag</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>Pending               <span class="token comment">// total pending messages</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>LastDeliveredID       <span class="token comment">// last delivered message ID</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>LastDeliveredDuration <span class="token comment">// time since last delivered message</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>LowerID               <span class="token comment">// lowest pending message ID</span></span>
<span class="line">        stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>LowerDuration         <span class="token comment">// time since lowest pending message</span></span>
<span class="line">        <span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> c <span class="token operator">:=</span> <span class="token keyword">range</span> stat<span class="token punctuation">.</span>Group<span class="token punctuation">.</span>Consumers <span class="token punctuation">{</span></span>
<span class="line">            c<span class="token punctuation">.</span>Name    <span class="token comment">// consumer name</span></span>
<span class="line">            c<span class="token punctuation">.</span>Pending <span class="token comment">// pending messages for this consumer</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Multiple streams</span></span>
<span class="line">stats<span class="token punctuation">,</span> err <span class="token operator">:=</span> broker<span class="token punctuation">.</span><span class="token function">GetStreamsStatistics</span><span class="token punctuation">(</span><span class="token string">&quot;dirty_AllChanges&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;dirty_NewUsers&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,59)]))}const c=s(p,[["render",i]]),u=JSON.parse('{"path":"/guide/dirty_streams.html","title":"Dirty Streams","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772273114000,"contributors":[{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":5,"url":"https://github.com/lukaszlato"},{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":1}],"changelog":[{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"bfc685f185295c4935fe51069bacb3c93ec9beda","time":1764664948000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"543b75a617cfdd17e7cf88ab1b077d0d76abe156","time":1763554211000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"2c88845a3c9e15a182e098d96677a1dc845d243a","time":1762270602000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"989d4c2ad31c7160dc4f2439beb55443c7e72b30","time":1762270480000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"3e0d22a079ad480286919d95dcff3137e4fa5f4c","time":1762264658000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"}]},"filePathRelative":"guide/dirty_streams.md"}');export{c as comp,u as data};
